const data = $input.first().json.news || [];
const filtered = data
  .filter(item => item.image && item.image !== 'None')
  .map(item => ({
    title: item.title,
    description: item.description,
    url: item.url,
    image: item.image,
    category: Array.isArray(item.category) ? item.category[0] : (item.category || 'general'),
    country: null
  }));
const newsB64 = Buffer.from(JSON.stringify(filtered)).toString('base64');
return [{ json: { newsB64, filteredData: filtered } }];
